INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (1, 1, 'Darurat vs investasi', 'Sebelum mulai investasi jangka panjang, prioritas paling masuk akal biasanya?', '["Beli gadget biar semangat","Siapkan dana darurat dulu","Ikut grup sinyal cepat"]'::jsonb, 'Siapkan dana darurat dulu', 'Investasi gede-gedean, tapi ogut nol pas motor rusak—aneh nggak?', 'Tanpa penyangga, satu kejadian bisa membongkar semua rencana sekaligus.', 'Dana darurat menahan goncangan seperti utang mendadak atau hilang penghasilan sementara tanpa jual aset terburu-buru.', 'Pagar dulu, baru panen.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (2, 1, 'Tracking pengeluaran', 'Biasanya orang salah kira kaya apa soal pengeluaran harian?', '["Pasti kebanyakan belanja besar","Irit-irit tapi hemat kecil lenyap tanpa sadar","Hemat itu haram"]'::jsonb, 'Irit-irit tapi hemat kecil lenyap tanpa sadar', 'Kopi dan ojol nggak kerasa—tapi kok akhir bulan habis?', 'Yang membocorkan dompet sering hal receh yang enggak kecatat.', 'Biaya kecil berulang menumpuk; tanpa catatan, otak mengira masih aman padahal totalnya besar.', 'Yang receh, sering yang membunuh.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (3, 1, 'Utang kartu kredit', 'Bayar minimum kartu kredit artinya apa dampaknya?', '["Utangnya turun cepat","Bunga tetap jalan dan utang bisa menggumpal","Langsung bebas bunga"]'::jsonb, 'Bunga tetap jalan dan utang bisa menggumpal', 'Minimum payment terasa aman—bingung kok saldo nggak turun-turun?', 'Minimum hanya menunda, tidak mematikan masalah pokoknya.', 'Saldo tersisa tetap dikenakan bunga bulanan; lama-lama potonganmu banyak melayang ke bunga, bukan pokok.', 'Bayar minimum, utang rebahan.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (4, 1, 'Anggaran realistis', 'Anggaran paling sering gagal karena apa?', '["Terlalu ketat sampai mustahil","Terlalu besar tanpa target","Terlalu mudah"]'::jsonb, 'Terlalu ketat sampai mustahil', 'Rencana sebulan cuma mie—yakin bisa konsisten tiga bulan?', 'Kalau rasanya hukuman, orang pasti bolong-bolongin aturan sendiri.', 'Anggaran perlu napas ruang kecil untuk hal wajar agar kamu tidak rebond belanja besar.', 'Realistis menang marathon.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (5, 1, 'Pajak dan potongan', 'Gaji "bersih" di slip itu biasanya sudah termasuk apa?', '["Potongan pajak dan iuran wajib sesuai aturan","Bonus tahun depan","Keuntungan investasi"]'::jsonb, 'Potongan pajak dan iuran wajib sesuai aturan', 'Kok take-home beda jauh dari angka kontrak kerja?', 'Yang bisa dibudget itu uang yang benar-benar masuk rekeningmu.', 'Slip gaji mencerminkan pemotongan legal; anggarkan dari nominal neto agar tidak kepedean.', 'Hitung neto, bukan bruto.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (6, 1, 'Asuransi kesehatan', 'Fungsi dasar asuransi kesehatan dalam keuangan pribadi?', '["Ganti gadget setiap tahun","Membantu tagihan medis besar tak terduga","Jamin investasi cuan"]'::jsonb, 'Membantu tagihan medis besar tak terduga', 'Sehat-sehat aja—kenapa bayar premi tiap bulan?', 'Yang kamu beli bukan "investasi", tapi pengaman mencegah bangkrut medis.', 'Satu rawat inap bisa menghapus tabungan; premi memindahkan sebagian risiko ke pihak asuransi.', 'Bayar kecil, lindung besar.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (7, 1, 'Tabungan vs investasi', 'Tabungan idealnya untuk apa dibanding investasi?', '["Tujuan jangka pendek dan likuid","Mengejar return tertinggi tanpa batas","Menghindari pajak sepenuhnya"]'::jsonb, 'Tujuan jangka pendek dan likuid', 'Semua uang diparkir investasi—waktu butuh duit minggu ini gimana?', 'Likuiditas itu bukan kemewahan; itu oksigen keputusan harian.', 'Tabungan dekat jangka menjaga kamu tidak jual aset pas pasar lagi jelek atau kena denda.', 'Pisahkan dana dekat dan jauh.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (8, 1, 'Biaya admin tersembunyi', 'Biaya admin kecil bulanan sering terasa seperti apa?', '["Nol selamanya","Tetes demi tetes yang menumpuk","Selalu dikembalikan otomatis"]'::jsonb, 'Tetes demi tetes yang menumpuk', 'Bunga tabungan kecil, biaya admin kecil—kok tabungan malah mandeg?', 'Biaya tetap membunuh akun yang saldonya tipis.', 'Beberapa biaya flat memakan persentase besar kalau saldonya rendah jadi perlu pilih perbankan yang cocok.', 'Baca biaya, jangan asal.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (9, 1, 'Harga vs nilai', 'Barang diskon besar belum tentu murah jika apa?', '["Kamu tidak butuh sama sekali","Pasti lebih baik dari baru","Itu selalu investasi pasti"]'::jsonb, 'Kamu tidak butuh sama sekali', 'Diskon 70% tapi lemari sudah penuh—menang atau ketipu?', 'Harga murah tetap buang uang kalau beli barang yang tidak dipakai.', 'Nilai pakai menentukan presi; diskon memanipulasi rasa hemat padahal barang menganggur.', 'Hemat palsu tetap boros.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (10, 1, 'Minta tunggakan', 'Kenapa menunda tagihan rutin berbahaya?', '["Biasanya ada biaya denda atau bunga","Orang lain akan membayar otomatis","Tidak pernah ada konsekuensi"]'::jsonb, 'Biasanya ada biaya denda atau bunga', 'Ditunda dulu deh listrik—nanti bisa, kan?', 'Tunggakan membuat masalah kecil jadi bola salju biaya.', 'Denda dan bunga menambah beban; menyelesaikan rutin tepat waktu menjaga arus kas tetap bersih.', 'Bayar tepat waktu, hindari bola salju.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (11, 2, 'Trade-off harian', 'Setiap pilihan belanja berarti apa secara uang?', '["Gratis selamanya","Mengorbankan penggunaan uang di hal lain","Tidak mempengaruhi apa-apa"]'::jsonb, 'Mengorbankan penggunaan uang di hal lain', 'Beli ini artinya tidak beli itu—ngaku atau ngelak?', 'Uang terbatas memaksa urutan prioritas, bukan keajaiban.', 'Biaya peluang sederhana: rupiah yang dipakai A tidak bisa dipakai B pada saat yang sama.', 'Pilih A, berarti tolak B.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (12, 2, 'Gaya hidup naik', 'Lifestyle creep terjadi ketika apa?', '["Pengeluaran ikut naik begitu penghasilan naik","Orang tiba-tiba hemat ekstrem","Harga barang turun semua"]'::jsonb, 'Pengeluaran ikut naik begitu penghasilan naik', 'Gaji naik kok tabungan tetap kosong—hantu apa ini?', 'Tanpa aturan, gaji baru sering jadi standar belanja baru.', 'Kenaikan penghasilan mudah diserap gaya hidup; sisihkan dulu sebelum norma belanja berubah.', 'Naik gaji, jangan boros refleks.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (13, 2, 'FOMO belanja', 'FOMO belanja sering memicu keputusan seperti apa?', '["Beli karena takut ketinggalan tren","Beli setelah hitung butuh","Selalu menunggu diskon mati"]'::jsonb, 'Beli karena takut ketinggalan tren', 'Teman sudah punya; kamu belum—itu alasan yang cukup?', 'Tren memintamu membandingkan display bukan kebutuhan nyata.', 'FOMO melecut emosi ; jeda satu malam sering membedakan kebutuhan dan ketakutan sosial.', 'Jeda sehari, kurangi menyesal.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (14, 2, 'Hemat sementara', 'Mengapa diet belanja ekstrem sering gagal total?', '["Terlalu keras lalu rebound besar","Selalu berhasil tanpa lelah","Bank akan mengganti"]'::jsonb, 'Terlalu keras lalu rebound besar', 'Sebulan zero fun—yakin bulan depan tidak belanja balas dendam?', 'Kehidupan finansial sehat itu kebiasaan, bukan hukuman seumur hidup.', 'Pembatasan berlebihan meningkatkan risiko balas belanja; irama kecil lebih bertahan.', 'Konsisten kecil mengalahkan keras henti.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (15, 2, 'Uang dan identitas', 'Gunakan uang untuk bantal ego biasanya berujung apa?', '["Keputusan yang menguntungkan jangka panjang","Pameran status yang menguras tabungan","Pajak otomatis turun"]'::jsonb, 'Pameran status yang menguras tabungan', 'Brand mahal biar dihormati—siapa yang sebenarnya diuntungkan?', 'Harga status tidak bersih di tagihan kartu kamu setiap bulan.', 'Spending demi citra menambah beban rutin tanpa menambah keamanan finansial.', 'Hormati dompet, bukan penilaian orang.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (16, 2, 'Hadiah diri sendiri', 'Reward after payday sering jadi masalah jika apa?', '["Tidak dibatasi dan jadi kebiasaan otomatis","Selalu kecil dan jarang","Dibayar tunai saja"]'::jsonb, 'Tidak dibatasi dan jadi kebiasaan otomatis', 'Lelah kerja, ya wajar dong hajar checkout—atau jebakan?', 'Validasi lelah tidak harus bentuknya tabungan minus.', 'Hadiah berulang tanpa batas menyamar sebagai kebutuhan dan menggerus tujuan finansialmu.', 'Hadiah tanpa batas = bocor diam-diam.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (17, 2, 'Utang ke keluarga', 'Pinjam ke keluarga paling berisiko pada bagian apa?', '["Konflik dan ekspektasi tidak tertulis","Selalu ada kontrak resmi","Tidak ada emosi terlibat"]'::jsonb, 'Konflik dan ekspektasi tidak tertulis', 'Sinang cuma bilang nanti—nanti bisa resep pertikaian, lho.', 'Uang menempel pada hubungan ketika aturan bayarnya kabur.', 'Tanpa kesepakatan jelas, salah paham soal jadwal bunga sering meregang silaturahmi.', 'Sepakat tertulis, hindar drama.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (18, 2, 'Scarcity mindset', 'Mindset kelangkaan berlebihan bisa bikin apa?', '["Keputusan buruk karena panik jangka pendek","Selalu tenang","Investasi auto-optimal"]'::jsonb, 'Keputusan buruk karena panik jangka pendek', 'Merasa selalu kekurangan—yakin itu fakta atau filter otak?', 'Panik menyempitkan fokus sehingga hitung-hitungan mati rasa.', 'Tekanan kelangkaan memicu putusan tergesa; napas dan data membantu meredakan salah langkah.', 'Panik mempersempit, data memperlebar.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (19, 2, 'Tunda gaji', 'Pay-later memperhalus apa sebenarnya?', '["Rasa sakit pembayaran sekarang dengan utang nanti","Penghasilan tetap","Hilangnya semua tagihan"]'::jsonb, 'Rasa sakit pembayaran sekarang dengan utang nanti', 'Bayar belakangan terasa gratis—siapa yang bayar utangnya nanti?', 'Menunda rasa sakit bukan menghilangkan kewajiban.', 'Pay-later menunda beban; jika bertumpuk, tekanan bulan depan bisa lebih berat.', 'Tunda rasa, bukan tanggung jawab.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (20, 2, 'Gratis tapi mahal', 'Aplikasi ''gratis'' bisa mahal karena apa?', '["Data, iklan, dan perilaku belanja terarah","Tidak pernah ada model bisnis","Selalu tanpa kaitan uang"]'::jsonb, 'Data, iklan, dan perilaku belanja terarah', 'Produk gratis—kok perusahaannya tetap cuan besar?', 'Kalau kamu tidak membayar produk, kamu bisa jadi produknya.', 'Model gratis sering diisi iklan dan profil perilaku yang memicu belanja tidak direncanakan.', 'Gratis ada harga tersembunyi.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (21, 3, 'Apa itu saham', 'Membeli satu saham berarti secara sederhana kamu seperti apa?', '["Memiliki sebagian klaim atas perusahaan","Meminjam uang tanpa syarat","Menjamin dividen pasti"]'::jsonb, 'Memiliki sebagian klaim atas perusahaan', 'Kata orang ''beli perusahaan''—secara hukum kecil, itu benernya gimana?', 'Bukan magic coin; itu potongan kepemilikan yang sensitif kinerja bisnis.', 'Saham mewakili hak ekonomi terbatas sesuai porsi; bukan jaminan untung atau bisnis pribadi.', 'Saham = potongan bisnis, bukan janji.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (22, 3, 'Volatilitas', 'Harga saham naik-turun normal karena apa?', '["Permintaan penawaran dan ekspektasi pasar berubah","Perusahaan menjamin harga","Bank pusat set harga harian tetap"]'::jsonb, 'Permintaan penawaran dan ekspektasi pasar berubah', 'Kok bisa naik gila padahal berita kantor sepi—pasar mikir apa?', 'Harga itu voting jutaan orang, bukan skor akurat hari ini.', 'Harga mencerminkan percaya tidaknya pasar ke masa depan kas perusahaan dan suplai permintaan lembar saham.', 'Harga itu suara pasar, bukan fakta mutlak.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (23, 3, 'Diversifikasi saham', 'Memusatkan semua uang ke satu saham paling besar risikonya apa?', '["Satu skandal bisa hancurkan sebagian besar portofolio","Resiko otomatis nol","Return selalu lebih tinggi"]'::jsonb, 'Satu skandal bisa hancurkan sebagian besar portofolio', 'Yakin banget satu emiten—kalau kuartalnya zonk, tidur masih tenang?', 'Koncentrasi itu taruhan, bukan rencana pensiun yang rapih.', 'Satu perusahaan bisa gagal spesifik; penebaran mengurangi dampak satu kejadian buruk.', 'Satu kantong, satu petaka.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (24, 3, 'Dividen saham', 'Dividen perusahaan diumumkan perusahaan itu artinya apa?', '["Bukan jaminan selamanya sama dan bisa berubah","Selalu naik tiap tahun tanpa syarat","Otomatis menjamin harga saham naik"]'::jsonb, 'Bukan jaminan selamanya sama dan bisa berubah', 'Dividen tahun lalu besar—otomatis tahun ini sama, kan?', 'Kebijakan dividen bergantung kas dan strategi direksi, bukan janji abadi.', 'Dividen adalah keputusan rapat dan bisa dipangkas saat tekanan bisnis atau investasi internal.', 'Dividen tadi, bukan kontrak abadi.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (25, 3, 'Emiten rugi', 'Perusahaan untung akuntansi tapi saham turun bisa terjadi karena apa?', '["Ekspektasi pasar lebih tinggi dari realita","Harga tidak pernah berubah","Semua berita selalu bagus"]'::jsonb, 'Ekspektasi pasar lebih tinggi dari realita', 'Laba naik kok harga jeblok—orang pasar bodoh semua?', 'Market sudah menghargai cerita masa depan, bukan hanya angka kemarin.', 'Jika hasil di bawah ekspektasi yang sudah dibayar di harga, koreksi bisa datang cepat.', 'Pasaran harga ekspektasi, bukan masa lalu saja.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (26, 3, 'Right issue', 'Right issue pada intinya meminta pemegang saham apa?', '["Ikut tambah modal dengan hak membeli lembar baru","Otomatis terjual saham tanpa pilihan","Menghapus kepemilikan tanpa prosedur"]'::jsonb, 'Ikut tambah modal dengan hak membeli lembar baru', 'Dibilang ''hak''—kok rasanya dipaksa buka dompet lagi?', 'Perusahaan cari dana segar; kamu dipilih ikut atau encer kepemilikan.', 'Right issue menawarkan lembar baru biasanya di diskon agar pemegang lama tidak terlalu kena encer.', 'Hak beli, bukan angpao gratis.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (27, 3, 'Likuiditas saham', 'Saham illiquid berarti risiko apa bagi investor kecil?', '["Sulit jual cepat tanpa gerak harga besar","Selalu mudah jual kapan saja","Tidak ada risiko"]'::jsonb, 'Sulit jual cepat tanpa gerak harga besar', 'Naik di layar tapi order jual nggak ketemu pembeli—kenapa?', 'Harga kutipan bukan jaminan transaksi nyata beres cepat.', 'Volume tipis bikin spread lebar; keluar besar bisa mendorong harga turun saat jual.', 'Kutipan indah belum tentu bisa laku.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (28, 3, 'Market cap', 'Market cap besar secara kasar menandakan apa?', '["Ukuran nilai pasar kumulatif, bukan jaminan aman","Prospek pasti tanpa risiko","Harga saham murah otomatis"]'::jsonb, 'Ukuran nilai pasar kumulatif, bukan jaminan aman', 'Blue chip kan jaminan tenang—pernah dengar jatuh juga?', 'Besar tidak sama dengan anti rugi; hanya skala dan likuid biasanya lebih baik.', 'Kapitalisasi harga kali lembar; perusahaan besar tetap bisa salah strategi atau kena siklus.', 'Besar bukan sinonim aman.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (29, 3, 'Short term noise', 'Komentar harian sosmed soal saham paling sering apa?', '["Noise emosional, jarang konteks utuh","Rahasia pasti cuan","Panduan resmi regulator"]'::jsonb, 'Noise emosional, jarang konteks utuh', 'Thread panjang bilang ''pasti meledak''—itu riset atau dopamin?', 'Kecepatan sosmed mengalahkan kedalaman cek fakta.', 'Sinyal singkat sering tanpa fundamental dan horizon; filter sumber dan horizonmu sendiri.', 'Bising online bukan rencana investasi.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (30, 3, 'Buy the dip', 'Beli saat turun tanpa analisis berisiko jadi apa?', '["Menangkap pisau yang masih jatuh","Strategi bebas risiko","Otomatis untung"]'::jsonb, 'Menangkap pisau yang masih jatuh', 'Diskon 30% dari puncak—pasti murah, kan?', 'Harga turun belum otomatis artinya sudah murah secara bisnis.', 'Penurunan bisa berlanjut jika masalah fundamental; averaging butuh alasan, bukan hanya harga.', 'Turun belum tentu murah.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (31, 4, 'Obligasi dasar', 'Obligasi pada dasarnya hubungan seperti apa antara investor dan penerbit?', '["Investor meminjamkan uang dan terima imbal hasil terjadwal","Investor membeli porsi kepemilikan perusahaan","Investor otomatis pemilik operasional"]'::jsonb, 'Investor meminjamkan uang dan terima imbal hasil terjadwal', 'Dibilang ''surat utang''—kok sering disebut aman dibanding saham?', 'Kamu kreditur, bukan pemilik; janji utang lebih kaku dari laba saham.', 'Penerbit wajib bayar kupon dan pokok sesuai struktur hingga kecuali gagal bayar kredit.', 'Obligasi = pinjamkan, bukan miliki.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (32, 4, 'Suku bunga naik', 'Saat suku bunga naik, harga obligasi yang sudah beredar cenderung?', '["Turun karena imbalan baru lebih menarik","Naik otomatis selalu","Tidak pernah berubah"]'::jsonb, 'Turun karena imbalan baru lebih menarik', 'Bunga naik kok portofolio obligasi saya merah juga?', 'Versi lama terlihat kurang menarik dibanding surat utang baru.', 'Obligasi lama punya kupon tetap; investor menuntut diskon harga agar yield kompetitif naik.', 'Bunga naik, harga obligasi sering remuk.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (33, 4, 'Risiko gagal bayar', 'Utang pemerintah vs korporasi, risiko gagal bayar korporasi biasanya?', '["Lebih tinggi secara historis peringkat umum","Selalu nol di semua negara","Sama pasti dengan semua negara"]'::jsonb, 'Lebih tinggi secara historis peringkat umum', 'Yield korporasi lebih gede—itu bonus apa peringatan?', 'Imbal lebih tinggi sering membayar asuransi sepotong risiko kepercayaan.', 'Kredit korporasi bergantung bisnis dan leverage; default rate historis beda dengan negara stabil.', 'Yield lebih tinggi, baca risiko dulu.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (34, 4, 'Duration', 'Obligasi jatuh tempo panjang sensitifnya pada suku bunga biasanya?', '["Lebih besar dibanding obligasi tenor pendek","Selalu sama tidak peduli tenor","Tidak pernah sensitif"]'::jsonb, 'Lebih besar dibanding obligasi tenor pendek', 'Tenor panjang imbalannya gede—tapi kok goyangannya juga gede?', 'Masa panjang memperbesar jarak harga ke perubahan suku bunga.', 'Durasi panjang meningkatkan volatilitas harga walaupun kupon tetap terasa stabil di buku.', 'Panjang tenor, goyang bunga kerasa.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (35, 4, 'Nilai pari', 'Nilai nominal obligasi biasanya dipakai untuk apa?', '["Acuan pokok di titik jatuh tempo kontrak","Harga pasar harian saham","Dividen wajib tahunan"]'::jsonb, 'Acuan pokok di titik jatuh tempo kontrak', 'Nilai 100 di kertas tapi pasar 95—mana yang relevan?', 'Pari janji pokok akhir; harga pasar hari terus menyesuaikan suku bunga.', 'Harga di bawah pari mungkin diskon risiko atau suku bunga lebih tinggi dari kupon obligasi ini.', 'Pari = janji akhir, harga harian beda.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (36, 4, 'Pasar obligasi sekunder', 'Beli obligasi di pasar sekunder artinya apa?', '["Membeli dari investor lain, tidak selalu dari penerbit langsung","Selalu dari pemerintah baru cetak","Tanpa harga pasar sama sekali"]'::jsonb, 'Membeli dari investor lain, tidak selalu dari penerbit langsung', 'Beli obligasi di aplikasi—lawannya siapa sebenarnya?', 'Kamu bisa menebus likuiditas investor lain dengan harga bergerak.', 'Sekunder mengikuti penawaran permintaan dan suku bunga; yield beli final bisa beda kupon asli.', 'Sekunder = beli dari sesama, harga hidup.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (37, 4, 'Inflasi vs kupon tetap', 'Inflasi tinggi dengan kupon obligasi tetap artinya daya beli bunga?', '["Bisa tergerus meski nominal tetap masuk","Selalu meningkat otomatis","Tidak relevan bagi investor"]'::jsonb, 'Bisa tergerus meski nominal tetap masuk', 'Bunga kupon enak—tapi rokok kok makin mahal tiap tahun?', 'Nominal stabil tidak otomatis berarti daya beli stabil.', 'Inflasi mengurangi nilai riil arus kupon dan pokok kecuali ada proteksi indeks tertentu produk.', 'Nominal rapi, daya beli bisa luka.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (38, 4, 'Reinvestasi kupon', 'Mengabaikan reinvestasi kupon mengaburkan apa?', '["Total return sebenarnya jangka panjang","Risiko gagal bayar saja","Hanya pajak, bukan yield"]'::jsonb, 'Total return sebenarnya jangka panjang', 'Kupon dicairkan terus—kompon bunganya bolong di mana?', 'Uang bekerja ulang memperbesar efek kompaun pada obligasi total return.', 'Menyatukan kupon pada yield serupa menambah total imbalan dibanding diamkan kas menganggur.', 'Kupon reinvest, return lengkap.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (39, 4, 'Obligasi vs deposito', 'Perbedaan kasar obligasi pasar vs deposito bank bagi ritel?', '["Obligasi harga pasar berflukturasi deposan nilai nominal lebih stabil","Sama persis tidak ada beda","Deposito selalu lebih berisiko"]'::jsonb, 'Obligasi harga pasar berflukturasi deposan nilai nominal lebih stabil', 'Keduanya di label ''pendapatan tetap''—kok satu goyang satu rata?', 'Mark-to-market obligasi berbeda mekanisme jaminan likuid bank sederhana.', 'Deposito biasanya kembali nominal jelas periode; obligasi pasar berubah harga sebelum jatuh tempo.', 'Bunga tetap tidak sama stabil harga.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (40, 4, 'Peringkat kredit', 'Peringkat turun untuk satu obligasi emiten mengisyaratkan apa?', '["Penilai pasar lihat risiko gagal bayar meningkat","Tidak ada arti","Otomatis negara ikut default"]'::jsonb, 'Penilai pasar lihat risiko gagal bayar meningkat', 'Rating turun satu strip—cuma drama analis?', 'Harga sering sudah react duluan; rating mengkonfirmasi kekhawatiran kolektif.', 'Rating agensi merangkum kemungkinan gagal bayar relatif; investor harus baca konteks bisnis juga.', 'Rating turun, tanya mengapa dulu.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (41, 5, 'ETF wadah', 'ETF pada dasarnya?', '["Keranjang aset diperdagangkan seperti satu saham","Satu obligasi pemerintah tunggal","Produk tanpa biaya sama sekali"]'::jsonb, 'Keranjang aset diperdagangkan seperti satu saham', 'Beli ''satu ticker'' tapi isinya ratusan saham—itu tipu visual atau efisiensi?', 'ETF menyatukan diversifikasi dan likuiditas bursa dalam satu klik.', 'Unit ETF mewakili pro-rata portofolio tracking indeks atau tema sesuai prospektus.', 'Satu ticker, banyak isi.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (42, 5, 'Expense ratio', 'Biaya expense ratio tahunan artinya?', '["Potongan kontinyu dari aset fund setelah biaya transaksi","Hanya biaya sekali beli saja","Tidak mempengaruhi return"]'::jsonb, 'Potongan kontinyu dari aset fund setelah biaya transaksi', 'Fee 0,2% kecil, kan—kalau dihitung 20 tahun?', 'Biaya kecil tahunan mengikis kompaun diam-diam tanpa invoice terpisah.', 'Rasio biaya mengurangi return neto pemegang unit setiap tahun secara mekanisme internal.', 'Fee kecil, kompaun tetap menggigit.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (43, 5, 'Tracking error', 'ETF bisa meleset dari indeks acuan karena?', '["Biaya, sampling, dividen, dan likuiditas rekonstruksi","Indeks selalu identik tanpa selisih","Hanya karena scam"]'::jsonb, 'Biaya, sampling, dividen, dan likuiditas rekonstruksi', 'Indeks naik 10% kok fund saya beda tipis—curang?', 'Menyalin indeks dunia nyata bukan copy-paste software.', 'Biaya internal dan metode sampling menyebabkan tracking error normal kecil namun ada.', 'Ikut indeks, bukan kunci gembok.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (44, 5, 'Tema sempit', 'ETF tematik sempit paling besar risikonya?', '["Koncentrasi satu narasi ekonomi","Diversifikasi otomatis sempurna","Tanpa volatilitas"]'::jsonb, 'Koncentrasi satu narasi ekonomi', 'ETF AI semua orang bahas—kalau narasi dingin, siapa menahan?', 'Tema sempit bukan diversifikasi luas meski label ETF.', 'Portofolio fokus industri atau tema satu arah sehingga koreksi sektor terasa penuh.', 'Tema keren, risiko tetap fokus.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (45, 5, 'Redemption mekanisme', 'ETF open-end dengan AP umumnya menyamakan harga unit dengan?', '["Nilai aset bersih underlying dikurangi biaya spread","Harga sembarang dealer","Tebakan harian"]'::jsonb, 'Nilai aset bersih underlying dikurangi biaya spread', 'Harga ETF beda sedikit dari isi laci asetnya—wajar atau salah?', 'Mekanisme penciptaan-redemption menjaga harga dekat NAV mayoritas waktu.', 'Authorized participant meng-arbitrase diskon premium sehingga menyamai koleksi aset mayoritas waktu.', 'ETF menggigit aset bawahnya.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (46, 5, 'Diversifikasi geografis', 'ETF indeks negara lain membantu apa?', '["Menyebar risiko domestik ke eksposur pasar lain","Menghapus seluruh risiko mata uang","Menjamin return lebih tinggi negeri"]'::jsonb, 'Menyebar risiko domestik ke eksposur pasar lain', 'Semua keranjang lokal—kalau rezim rumah sakit semua ikut?', 'Geografi lain tidak sempurna lindung tapi menambah sumber pengembalian.', 'Korelasi antar negara tidak satu; tabungan internasional menurunkan ketergantungan satu siklus.', 'Kanvas lebih luas, siklus beda.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (47, 5, 'Bid-ask spread', 'ETF kecil volume sering punya biaya tersembunyi apa?', '["Spread bid-ask lebar pada transaksi","Tidak ada biaya","Hanya pajak pemerintah pusat"]'::jsonb, 'Spread bid-ask lebar pada transaksi', 'Likuid tipis—yakin harga layar adalah harga dapatmu?', 'Beli di satu sisi spread, jual di sisi lain mengiris return.', 'Volume kecil membengkakkan spread; ETF besar umumnya lebih ketat biaya perdagangan.', 'Tipis likuid, tebal spread.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (48, 5, 'Rebalancing indeks', 'Strategi indeks cap-weight besar mengandung bias apa?', '["Pemenang masa lalu jadi bobot lebih besar otomatis","Selalu sama rata tanpa dominasi","Menghapus saham besar"]'::jsonb, 'Pemenang masa lalu jadi bobot lebih besar otomatis', 'Indeks ''pasif'' tapi kok ikut membesarkan juara lalu?', 'Cap-weight bukan netral cerita moral; itu mekanisme matematis pasar.', 'Saham besar bobot besar; kemenangan harga historis memperbesar porsi tanpa pilih fundamental manual.', 'Cap-weight ikut gelombang juara.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (49, 5, 'ETF vs reksa manual', 'ETF indeks biasanya menang di mana dibanding beli 50 saham sendiri?', '["Biaya transaksi dan waktu rekayasa lebih rendah","Selalu return lebih tinggi pasti","Tanpa risiko pasar"]'::jsonb, 'Biaya transaksi dan waktu rekayasa lebih rendah', 'Bisa koleksi manual—tapi punya waktu ibu rumah tangga fund manager?', 'Skala institusi menurunkan friksi untuk investor kecil.', 'Satu transaksi ETF menggantikan banyak komisi dan rekonstruksi berkala indeks profesional.', 'Biaya waktu juga modal.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (50, 5, 'ACWI vs domestik', 'ETF global ACWI intinya menambah apa dibanding hanya domestik?', '["Eksposur lintas negara dan sektor berbeda","Menghapus volatilitas seluruhnya","Satu negara saja"]'::jsonb, 'Eksposur lintas negara dan sektor berbeda', 'Portfolio cuma bendera satu negara—yakin dunia berputar di situ saja?', 'Eksposur global mengurangi taruhan satu rezim politik dan satu siklus domestik.', 'ACWI mencampur pasar maju dan emerging; hubungan tidak selalu bergerak serempak.', 'Dunia lebih luas dari kode negara.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (51, 6, 'Dividen kas', 'Dividen tunai yang dibayarkan ke investor berasal dari mana idealnya?', '["Arus kas operasional stabil perusahaan","Utang jangka panjang otomatis","Murni penerbitan saham baru tanpa bisnis"]'::jsonb, 'Arus kas operasional stabil perusahaan', 'Dividen dicairin tiap kuartal—pasti dari operasi sehat, kan wajib?', 'Kalau bayar dari utang susun struktur, bahaya menyusul.', 'Dividen sehat biasanya didukung laba berulang dan kas operasi, bukan akuntansi gimmick.', 'Cek sumber kas, bukan hanya nominal.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (52, 6, 'Yield tinggi', 'Yield dividen sangat tinggi sering isyarat apa?', '["Harga saham jatuh atau payout tidak berkelanjutan","Selalu kabar baik","Pasti bank sentral setuju"]'::jsonb, 'Harga saham jatuh atau payout tidak berkelanjutan', 'Yield 15% menggoda—itu hadiah atau sirene?', 'Yield naik bisa karena harga ambruk mencipta ilusi manis.', 'Dividen dibagi harga; harga turun drastis membengkak yield tanpa meningkatkan kesehatan bisnis.', 'Yield manis, cek harganya dulu.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (53, 6, 'Dividen vs pertumbuhan', 'Perusahaan fase pertumbuhan sering memilih apa dengan laba?', '["Reinvestasi internal ketimbang dividen besar","Dividen 100% laba selalu","Jual semua aset"]'::jsonb, 'Reinvestasi internal ketimbang dividen besar', 'Kenapa teknologi banyak yang nol dividen padahal untung?', 'Laba diputar proyek kadang lebih menarik bagi direksi daripada cair kemu.', 'Retained earnings mendanai R&D dan ekspansi; dividen menyerahkan pilihan kepada investor.', 'Tumbuh atau cair, pilih strategi.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (54, 6, 'Pajak dividen', 'Dividen untuk investor pribadi biasanya?', '["Bisa kena pajak sesuai ketentuan wilayah masing-masing","Selalu bebas pajak otomatis","Menghapus kewajiban lapor apa pun"]'::jsonb, 'Bisa kena pajak sesuai ketentuan wilayah masing-masing', 'Neto rekening kok beda dari angka bruto dividen?', 'Pemotongan pajak mungkin mengurangi yang kamu pegang sebenarnya.', 'Tarif pajak dividen berbeda negara dan tipe investor; hitung after-tax untuk strategi jangka panjang.', 'Bunga cuan, baca pajaknya.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (55, 6, 'DRIP psikologi', 'Program reinvestasi dividen otomatis membantu apa?', '["Kompaun disiplin tanpa godaan cash di tangan","Menghapus risiko pasar","Menjamin harga beli selalu dasar"]'::jsonb, 'Kompaun disiplin tanpa godaan cash di tangan', 'Cair receh ke rekening—kenapa tidak langsung belanja kecil saja?', 'Otomatis menghindarkan dividen menguap pada kopi tidak perlu.', 'Reinvestasi membeli lebih banyak unit sehingga arus dividen masa depan bisa tumbuh berlapis.', 'Otomatis kunci kompaun kecil.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (56, 6, 'Ex-dividend date', 'Beli saham tepat sebelum ex-date tanpa riset artinya?', '["Mungkin bayar harga sudah naik refleksi dividen","Pasti untung dividen bebas risiko","Harga tidak pernah menyesuaikan"]'::jsonb, 'Mungkin bayar harga sudah naik refleksi dividen', 'Kejar tanggal ex-div—pasti dapat potongan gratis?', 'Pasar sering menyematkan ekspektasi dividen ke harga sebelum ex.', 'Harga cenderung turun sekitar dividen pada ex-date; kejar tanggal bukan strategi ajaib.', 'Tanggal ex bukan kupon gratis.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (57, 6, 'Cover cashflow', 'Mengandalkan dividen saja untuk biaya hidup berisiko karena?', '["Dividen bisa dipotong saat tekanan bisnis","Selalu naik linear tiap tahun","Tidak pernah berubah"]'::jsonb, 'Dividen bisa dipotong saat tekanan bisnis', 'Bills fix, dividen tidak kontrak sewa—cocok dipaksakan full?', 'Arus dividen variabel menggoyang rencana hidup kaku.', 'Krisis kas perusahaan bisa memotong payout; dana darurat menyamakan goyangan dividen turun.', 'Dividen bukan gaji tetap.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (58, 6, 'Preferen istilah', 'Saham preferen sering menonjolkan apa dibanding common?', '["Kupon dividen lebih terjadwal tapi biasanya tanpa suara penuh","Voting penuh seperti pemilik operasional","Harga pasti tidak volatil sama sekali"]'::jsonb, 'Kupon dividen lebih terjadwal tapi biasanya tanpa suara penuh', 'Preferen kedengaran istimewa—tapi mewahnya di bagian mana?', 'Kamu menukar suara pemegang biasa untuk struktur arus lebih tebal sering.', 'Preferen menyerupai utang hibrida dengan dividen prioritas namun upside harga terbatas sering.', 'Preferen: arus di depan, suara di belakang.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (59, 6, 'Pemotongan dividen', 'Jika perusahaan memotong dividen drastis, investor harus menilai?', '["Apakah pemotongan melindungi struktur jangka panjang atau sinyal kerusakan","Hanya emosi jangka pendek","Otomatis jual tanpa baca"]'::jsonb, 'Apakah pemotongan melindungi struktur jangka panjang atau sinyal kerusakan', 'Dividen dipotong setengah—itu berhenti merawat atau operasi goyah?', 'Pemotongan bisa strategi bertahan atau alarm merah kontekstual.', 'Baca laporan arus kas dan utang; kadang potongan menyelamatkan perusahaan dari gagal bayar.', 'Potong dividend, baca narasi kas.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (60, 6, 'Total return', 'Total return saham mencakup apa selain perubahan harga?', '["Dividen yang direinvest atau ditarik","Hanya harga tutup harian","Hanya berita positif"]'::jsonb, 'Dividen yang direinvest atau ditarik', 'Saham flat dua tahun—pasti nol return, bener?', 'Arus dividen bisa menutupi ilusi harga diam.', 'Investor harus menghitung return termasuk yield dividen reinvestasi untuk gambaran jujur.', 'Harga diam belum cerita penuh.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (61, 7, 'Aset spekulatif', 'Banyak kripto dipegang terutama karena ekspektasi apa?', '["Naik harga spekulatif bukan arus kas bisnis","Arus kas dividen konstan seperti obligasi","Jaminan hukum simpanan bank"]'::jsonb, 'Naik harga spekulatif bukan arus kas bisnis', 'Dibilang masa depan keuangan—tapi kemarin dompet juga masa depanmu, kan?', 'Spekulasi bukan salah otomatis; menyamar sebagai rencana pensiun itu masalahnya.', 'Nilai banyak token bergantung sentimen dan likuiditas tanpa klaim arus kas kontraktual seperti obligasi.', 'Spekulasi jelas, jangan dianggap gaji.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (62, 7, 'Volatilitas ekstrem', 'Kripto sering lebih bergelombang dari saham tradisional karena?', '["Likuiditas tipis pasangan dan leverage spekulatif tinggi","Regulasi membuat harga nol volatilitas","Semua harga dipatok bank"]'::jsonb, 'Likuiditas tipis pasangan dan leverage spekulatif tinggi', 'Naik dua puluh persen sebelum makan siang—senang atau waspada?', 'Gelombang besar mudah memicu keputusan FOMO dan panic dua arah.', 'Pasar 24/7 dengan leverage retail dan narasi cepat memperbesar ayunan harga harian.', 'Gelombang besar, sabar kunci.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (63, 7, 'Kunci dompet', 'Kehilangan private key pada wallet non-custodial artinya?', '["Aset praktis tidak bisa dipulihkan tanpa backup","Bank akan mengembalikan otomatis","Regulator menyimpan salinan"]'::jsonb, 'Aset praktis tidak bisa dipulihkan tanpa backup', 'Tanpa kata sandi dompet, tukang kunci pun angkat tangan?', 'Desentral berarti tanggung jawab penuh di pihakmu sendiri.', 'Tanpa frase cadangan aman, tidak ada mekanisme reset seperti akun perbankan.', 'Tanpa cadangan, hilang permanen.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (64, 7, 'Stablecoin', 'Stablecoin di dunia nyata masih bisa mengalami apa?', '["Nilai lepas pagar sementara atau risiko penerbit","Harga pasti bebas risiko selamanya","Cadangan selalu audit wajar tanpa celah"]'::jsonb, 'Nilai lepas pagar sementara atau risiko penerbit', 'Dollar digital—kok pernah goyang jauh dari satu juga?', 'Jangkar butuh kepercayaan cadangan dan mekanisme pasar stabil.', 'Risiko penerbit, cadangan, dan likuiditas bisa membuat stablecoin sementara lepas jangkar di sejarah.', 'Stabil nama, belum tentu stabil risiko.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (65, 7, 'Rug pull', 'Proyek token baru tanpa tim jelas risiko klasik apa?', '["Rug pull atau likuiditas dicabut curang","Garansi regulator nasional","Return fixed seumur hidup"]'::jsonb, 'Rug pull atau likuiditas dicabut curang', 'APR taman bunga—tim anonim—masuk sekarang, katanya?', 'Imbal tidak wajar + transparansi nol = pola peringatan berulang.', 'Likuiditas pool bisa ditarik developer curang meninggalkan token tak terjual worth.', 'APR tinggi + anonim = waspada.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (66, 7, 'Biaya jaringan', 'Transfer on-chain bisa mahal saat apa?', '["Kongesti mempool dan lelang prioritas transaksi","Selalu gratis tiap jaringan","Hanya tergantung warna logo"]'::jsonb, 'Kongesti mempool dan lelang prioritas transaksi', 'Kirim sepuluh dolar, biaya network dua puluh—masih masuk akal?', 'Biaya tidak linear; jam sibuk bisa membunuh transaksi kecil.', 'Miner atau validator memprioritaskan fee tinggi ketika blok penuh sehingga biaya melonjak.', 'On-chain sibuk, biaya membengkak.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (67, 7, 'Pajak kripto', 'Untung jual kripto di banyak negara biasanya bagaimana secara pajak?', '["Bisa kena pajak capital gain sesuai aturan setempat","Selalu bebas karena aset digital","Tidak perlu lapor apa pun"]'::jsonb, 'Bisa kena pajak capital gain sesuai aturan setempat', 'Teman bilang pajak tidak kejar kripto—yakin hukum tidur?', 'Regulasi berubah; catat masuk keluar bukti transaksi.', 'Banyak yurisdiksi memperlakukan aktivitas crypto sebagai peristiwa pajak realisasi ketika dijual.', 'Catat transaksi, jangan kaget pajak.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (68, 7, 'Leverage kripto', 'Leverage futures crypto retail sering berujung apa?', '["Likuidasi cepat saat volatilitas kecil","Perlindungan penuh modal","Menghapus risiko selamanya"]'::jsonb, 'Likuidasi cepat saat volatilitas kecil', 'Bunga kecil, leverage besar—kok akun bisa nol membacanya?', 'Ayunan pasar makan margin lebih cepat dari reaksi manusia.', 'Posisi leverage dipanggil margin call ketika pergerakan harga menyerang kolam jaminanmu.', 'Leverage besar, sikat akun cepat.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (69, 7, 'Narratif media', 'Narasumber sosmed crypto sering memicu apa?', '["Herding dan putusan FOMO tanpa uji tuntas","Riset mendalam otomatis untuk penonton","Harga dipatok ilmiah"]'::jsonb, 'Herding dan putusan FOMO tanpa uji tuntas', 'Influencer jual token—berapa orang uji tuntas beneran?', 'Validasi sosial bukan laporan keuangan bernomor halaman.', 'Narasi cepat mengalahkan baca whitepaper; FOMO meningkatkan volatilitas herding retail.', 'Viral bukan verifikasi.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (70, 7, 'Cold vs hot wallet', 'Cold wallet bertujuan mengurangi risiko apa?', '["Peretas online mencuri kunci dari perangkat selalu terhubung","Menghapus pajak otomatis","Menjamin harga tidak turun"]'::jsonb, 'Peretas online mencuri kunci dari perangkat selalu terhubung', 'Semua aset di aplikasi panas—bobol sekali habis semua?', 'Memisahkan kunci dari internet menurunkan permukaan serangan digital.', 'Cold storage menyimpan private key offline sehingga remote exploit lebih sulit tanpa akses fisik.', 'Pisahkan kunci dari internet.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (71, 8, 'Siklus bisnis', 'Fase resesi ringan biasanya menekan apa konsumen?', '["Pendapatan diskresioner dan kepercayaan belanja","Harga sembako menjadi nol","Semua obligasi otomatis default"]'::jsonb, 'Pendapatan diskresioner dan kepercayaan belanja', 'Resesi kata ekonomi—kok dompetmu juga ikut ngerem?', 'Siklus ekonomi real mempengaruhi penjualan perusahaan biasa.', 'Permintaan turun pada barang tidak wajib sehingga laba sektor sensitif siklus goyah.', 'Siklus ekonomi sentuh dompet dulu.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (72, 8, 'Yield curve', 'Yield curve terbalik sering dibaca pasar sebagai sinyal apa?', '["Kekhawatiran pertumbuhan masa depan melambat","Pasti inflasi nol mendatang","Jam pasar pasti naik besok"]'::jsonb, 'Kekhawatiran pertumbuhan masa depan melambat', 'Bunga panjang lebih kecil dari pendek—itu puzzle atau alarm?', 'Kurva mencerminkan ekspektasi kolektif investor, bukan ramalan pasti.', 'Investor mungkin membeli obligasi panjang mendorong yield turun saat mencari lindung resesi.', 'Kurva membungkuk, pasar waspada.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (73, 8, 'Inflasi inti', 'Inti inflasi sering membuang komponen apa agar lebih halus?', '["Harga energi dan makanan yang sangat bergejolak","Semua komponen tanpa pengecualian","Hanya pajak rumah saja"]'::jsonb, 'Harga energi dan makanan yang sangat bergejolak', 'Angka inti tenang tapi tagihan rumah tetap panas—siapa dibohongi?', 'Metrik beda lensa; pengalaman harian bisa tidak sinkron satu angka agregat.', 'Core mengecualikan komponen volatil menjadikan sinyal tren domestik demand lebih jelas bagi kebijakan.', 'Inti tenang, tagihan tetap nyata.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (74, 8, 'Kebijakan moneter', 'Suku bunga naik oleh bank sentral bertujuan umum?', '["Menahan tekanan inflasi agregat permintaan","Memastikan saham naik selamanya","Menghapus semua utang rumah tangga"]'::jsonb, 'Menahan tekanan inflasi agregat permintaan', 'Pinjaman rumah membengkak—kenapa otoritas sengaja memeras?', 'Obat inflasi sering pahit untuk dompet berutang jangka pendek.', 'Suku lebih tinggi menaikan biaya pinjam sehingga melambat konsumsi dan investasi terlalu panas.', 'Obat inflasi rasanya pahit.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (75, 8, 'Fiskal stimulus', 'Stimulus fiskal besar bisa berisiko apa?', '["Tekanan inflasi jika pemandangan penawaran kaku","Menghapus semua kemiskinan instan","Membuat suku bunga obligasi turun permanen"]'::jsonb, 'Tekanan inflasi jika pemandangan penawaran kaku', 'Voucher dan proyek infrastruktur—kok harga bahan ikut naik semua?', 'Permintaan dipompa cepat menabrak kapasitas produksi terbatas.', 'Jika penawaran tidak ikut melebar, uang tambahan mengejar barang yang sama mendorong harga.', 'Pompa permintaan, tekan penawaran.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (76, 8, 'Nilai tukar', 'Mata uang domestik melemah terhadap asing artinya kasar bagi importir?', '["Biaya barang impor naik di rupiah","Barang impor otomatis jatuh harga","Tidak ada dampak perdagangan"]'::jsonb, 'Biaya barang impor naik di rupiah', 'Dollar naik sedikit saja—kok harga ponsel ikut melompat?', 'Nilai tukar memindahkan daya beli lintas negara secara brutal.', 'Import membayar asing; pelemahan domestik menambah rupiah per unit komoditas impor.', 'Rupiah lemah, impor meriang.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (77, 8, 'Leading indicators', 'Indikator awal seperti pesanan pabrik baru membantu apa?', '["Memberi petunjuk arah ekonomi beberapa bulan ke depan","Menceritakan masa lalu persis tanpa noise","Menjamin return portofolio"]'::jsonb, 'Memberi petunjuk arah ekonomi beberapa bulan ke depan', 'Data baru keluar hijau—kok kantormu belum rekrut?', 'Indikator memimpin tidak selalu cocok pengalaman pribadi seketika.', 'Leading data memberi sinyal probabilistik bukan ramalan pasti tiap sektor serempak.', 'Petunjuk awal, bukan janji.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (78, 8, 'Geopolitik minyak', 'Guncangan pasokan energi global sering mempengaruhi apa domestik?', '["Inflasi input dan ongkos transport","Harga sembako gratis otomatis","Menghilangkan volatilitas saham"]'::jsonb, 'Inflasi input dan ongkos transport', 'Perang jauh sana—kok harga bensin sini ikut drama?', 'Rantai energi menghubungkan harga dunia ke tagihan harianmu.', 'Minyak naik mendorong biaya logistik dan produksi yang menetes ke konsumen.', 'Energlobal, dompet lokal.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (79, 8, 'Likuiditas global', 'Likuiditas keuangan global ketat biasanya membuat apa aset risiko?', '["Harga aset risiko tertekan dan spread melebar","Semua aset naik serempak","Tidak ada perubahan perilaku investor"]'::jsonb, 'Harga aset risiko tertekan dan spread melebar', 'Semua orang jual bersamaan—air pasar sedang surut?', 'Saat likuiditas kering, pembeli sejati langka sehingga harga geser besar.', 'Ketat kredit dan margin call memaksa lelang aset sehingga volatilitas klaster naik.', 'Air surut, batu semua kelihatan.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (80, 8, 'Proteksionisme', 'Tarif impor naik biasanya berdampak bagaimana ke konsumen domestik?', '["Harga barang terlindung naik dan pilihan lebih mahal","Semua harga turun pasti","Menghapus industri lokal sepenuhnya"]'::jsonb, 'Harga barang terlindung naik dan pilihan lebih mahal', 'Lindungi pabrik lokal—kenapa tagihan konsumen ikut membengkak?', 'Proteksi sering memindahkan biaya ke pembeli dalam negeri.', 'Tarif menaikkan biaya barang imput sehingga konsumen membayar lebih atau cari substitusi mahal.', 'Lindung industri, dompet ikut bayar.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (81, 9, 'Alokasi strategis', 'Alokasi aset strategis artinya fokus pada apa jangka panjang?', '["Proporsi kelas aset target sesuai tujuan toleransi risiko","Prediksi saham minggu depan satu nama","Menghindar diversifikasi total"]'::jsonb, 'Proporsi kelas aset target sesuai tujuan toleransi risiko', 'Beli saham keren satu demi satu—itu strategi atau hobi koleksi?', 'Rencana proporsi mencegah portofolio jadi kebetulan acak beruntung.', 'Alokasi strategis mengikat kelas besar ekuitas obligasi kas sebelum pilih sekuritas spesifik.', 'Kerangka besar dulu, ticker belakangan.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (82, 9, 'Rebalancing disiplin', 'Rebalancing periodik intinya?', '["Jual beli kembali ke bobot target mengendalikan drift risiko","Menjual semua saat takut saja","Beli hanya aset yang naik terus"]'::jsonb, 'Jual beli kembali ke bobot target mengendalikan drift risiko', 'Saham terbang bobotmu bengkak—itu kabar baik atau risiko diam-diam?', 'Kemenangan bisa menumpuk risiko tanpa sadar; rebalancing memotong ego pasar.', 'Menaikkan pemenang membuat portofolio lebih agresif dari rencana awal sehingga disiplin menjaga profil.', 'Menang besar bisa menggemukkan risiko.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (83, 9, 'Resiko vs horizon', 'Investor muda pensiun jauh biasanya dapat toleransi ekuitas lebih tinggi karena?', '["Mereka punya waktu menunggu pemulihan volatilitas","Mereka tidak pernah mengalami kerugian","Hukum melarang obligasi"]'::jsonb, 'Mereka punya waktu menunggu pemulihan volatilitas', 'Umur dua puluh ikut all-in saham aman secara teoritis—teori atau nyata?', 'Horizon panjang memungkinkan menunggu akhir siklus buruk tanpa cair paksa.', 'Risiko urutan return buruk lebih kecil saat tidak perlu tarik dana saat pasar jatuh dan pensiun masih jauh.', 'Waktu menyerap volatilitas.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (84, 9, 'Sequence risk', 'Tarik dana pensiun saat pasar jatuh di awal pensiun paling menyakitkan karena?', '["Portofolio sulit pulih saat penarikan bertubi-tubi dari nilai rendah","Tidak ada dampak sama sekali","Pasar pasti pulih besok pagi"]'::jsonb, 'Portofolio sulit pulih saat penarikan bertubi-tubi dari nilai rendah', 'Pensiunan pas crash—nasi telur atau sisa berantakan?', 'Penarikan saat nilai rendah mengunci kerugian cepat.', 'Urutan return buruk di awal pensiun memperparah risiko umur panjang saat tidak ada gaji mengisi.', 'Awal pensiun buruk, racun dosis tinggi.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (85, 9, 'Home bias', 'Portofolio cuma aset domestik artinya risiko apa?', '["Taruhan besar pada satu negara dan siklus regulasi","Diversifikasi sempurna otomatis","Menghapus risiko politik"]'::jsonb, 'Taruhan besar pada satu negara dan siklus regulasi', 'Semua reksa dari bendera sendiri—dunia di luar tidak goyang juga?', 'Kenyamanan rumah tidak meniadakan guncangan struktural satu negara.', 'Home bias membuat kamu sangat bergantung kinerja satu ekonomi dan satu mata uang domestik.', 'Rumah nyaman, risiko tetap kumpul.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (86, 9, 'Korelasi bukan konstanta', 'Korelasi antar aset di krisis sering?', '["Naik bersamaan saat panic selling meluas","Turun menjadi nol selamanya","Tetap nol sepanjang masa"]'::jsonb, 'Naik bersamaan saat panic selling meluas', 'Saham obligasi saling melengkapi—tapi 2008 siapa yang jamin?', 'Diversifikasi mengurangi risiko idiosinkratik, bukan meniadakan kontagion.', 'Saat likuiditas kritis, banyak aset dijual bersamaan sehingga perlindungan korelasi melemah sementara.', 'Krisis rapatkan korelasi sebentar.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (87, 9, 'Glide path', 'Glide path menuju pensiun biasanya menggeser apa?', '["Ekuitas menurun dan aset stabil naik dekat tarikan","Semua ke kripto besar","Obligasi nol selamanya"]'::jsonb, 'Ekuitas menurun dan aset stabil naik dekat tarikan', 'Mau pensiun lima tahun lagi masih full saham—tepat atau teledor?', 'Horizon memendek membutuhkan kurangi urutan risiko penarikan.', 'Mendekati pensiun, banyak rencana menurunkan bobot berfluktuasi tinggi demi urutan return aman.', 'Dekat tarik dana, kurangi guncangan.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (88, 9, 'Anggaran risiko', 'Anggaran risiko artinya alokasi apa terlebih dahulu?', '["Berapa volatilitas total yang sanggup ditahan","Ticker paling viral pekan ini","Prediksi bulan depan pasti"]'::jsonb, 'Berapa volatilitas total yang sanggup ditahan', 'Beli macam-macam aset—tapi goyang total portfoliomu masih kira-kira berapa?', 'Tanpa bingkai risiko, diversifikasi hanyalah daftar belanja acak.', 'Anggaran risiko menetapkan kerangka agregat dulu sebelum pilih sekuritas dan tuas utang.', 'Tetapkan goyang total, baru isi wadah.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (89, 9, 'Liability matching', 'Untuk biaya pensiun pasti dalam beberapa tahun, intuisi umum?', '["Prioritaskan instrumen stabil sesuai jadwal tagihan","Semua ke saham growth tanpa batas","Hindari hitungan tanggal sama sekali"]'::jsonb, 'Prioritaskan instrumen stabil sesuai jadwal tagihan', 'Tagihan RSU tahun depan ketemu portofolio spekulatif—cocok?', 'Mencocokkan jadwal kas keluar mengurangi paksa jual di waktu jelek.', 'Matching utang atau kebutuhan dengan durasi kas masuk menurunkan risiko likuidasi paksa.', 'Jadwal tagihan, jadwalkan aset.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (90, 9, 'Tactical drift', 'Tactical allocation besar tanpa aturan sering berujung?', '["Tebak waktu pasar emosional merusak rencana jangka panjang","Disiplin otomatis tanpa perlu kontrol","Hasil selalu mengalahkan indeks"]'::jsonb, 'Tebak waktu pasar emosional merusak rencana jangka panjang', 'Tweak bulanan bikin pintar—atau malah merusak rencana semula?', 'Tanpa aturan tertulis, taktik jadi ikut suara pasar harian.', 'Penyesuaian besar berulang tanpa kriteria objektif sering mengikuti suasana pasar ritel.', 'Taktis tanpa aturan, rencana buyar.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (91, 10, 'Aversi rugi', 'Aversi rugi membuat orang sering?', '["Menahan saham rugi terlalu lama dan jual untung terlalu cepat","Selalu netral emosional","Membeli di puncak tanpa ragu"]'::jsonb, 'Menahan saham rugi terlalu lama dan jual untung terlalu cepat', 'Rugi seratus ribu sakit lebih dari untung seratus ribu enak—wajar atau jebakan?', 'Otak membesar-besarkan sakit rugi dibanding senang untung nilai sama.', 'Aversi rugi memicu efek disposition yang merugikan portofolio disiplin jangka panjang.', 'Rasa rugi lebih tajam dari untung.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (92, 10, 'Jangkar harga', 'Jangkar pada harga beli sering bikin apa?', '["Tunggu ''balik modal'' padahal prospek sudah berubah","Putusan rasional tanpa bias","Otomatis cut loss tepat waktu"]'::jsonb, 'Tunggu ''balik modal'' padahal prospek sudah berubah', 'Nunggu balik seratus harga lama—itu sabar atau menolak kenyataan?', 'Harga masuk masa lalu jarang relevan untuk keputusan masa depan.', 'Anchoring ke biaya historis menghalangi evaluasi pada nilai intrinsik terkini objektif.', 'Biaya masa lalu bukan ramalan.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (93, 10, 'Bias konfirmasi', 'Konfirmasi bias membuat riset jadi apa?', '["Memungut fakta yang mendukung sudut murni tanpa uji lawan","Selalu netral statistik otomatis","Menghindari opini sepenuhnya"]'::jsonb, 'Memungut fakta yang mendukung sudut murni tanpa uji lawan', 'Artikel pertama yang kamu baca sudah sama pendapatmu—koinsidensi?', 'Riset sehat sengaja mencari bukti yang membantah teori sendiri.', 'Konfirmasi memperkuat keyakinan awal tanpa menyaring informasi kontradiktif relevan.', 'Cari fakta yang melawan teori.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (94, 10, 'Efek disposition', 'Jual pemenang dan peluk pecundang biasanya karena?', '["Menghindari penyesalan kristalisasi rugi dan mengunci kepuasan kecil","Strategi matematika optimal pasti","Acak tanpa pola"]'::jsonb, 'Menghindari penyesalan kristalisasi rugi dan mengunci kepuasan kecil', 'Cuan dikunci cepat, rugi dipeluk lama—siapa yang menang struktur?', 'Perilaku menjual bukti untung terasa enak dan menunda sakit rugi.', 'Disposition membuat portfoliomu membanjiri pecundang dan kehabisan pemenang potensi besar.', 'Potong rugi susah, padahal perlu.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (95, 10, 'Kepercayaan berlebihan', 'Trader percaya diri tinggi tanpa rekam jejak sering?', '["Menambah ukuran posisi di luar bukti statistik yang valid","Selalu sesuai prediksi pasar","Menghindar leverage total"]'::jsonb, 'Menambah ukuran posisi di luar bukti statistik yang valid', 'Tiga kali menang berturut—kamu jenius pasar atau kebetulan?', 'Menang beruntun membuat otak merasa punya keunggulan statistik palsu.', 'Kepercayaan berlebihan menaikkan tuas dan frekuensi jual beli tanpa bukti angka yang rapi.', 'Beruntun menang, belum bukti skill.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (96, 10, 'Akun mental', 'Uang bonus dipisahkan ''gratis'' dari gaji sering memicu?', '["Belanja impulsif seolah tidak dari tabungan utama","Hemat otomatis tanpa pengecualian","Perhitungan rasional identik semua sumber"]'::jsonb, 'Belanja impulsif seolah tidak dari tabungan utama', 'Angpao ''boleh foya''—tapi dompetmu kan satu, ya?', 'Membagi mental account mengubah perilaku padahal arus tetap sama.', 'Label sumber dana mengubah marginal propensity konsumsi tanpa mengubah kesehatan agregat.', 'Uang satu dompet, label beda perilaku.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (97, 10, 'Bias kini', 'Memilih untung kecil sekarang daripada lebih besar nanti menunjukkan?', '["Nilai kini dibesar-besarkan lawan masa depan","Kepatuhan rencana jangka panjang sempurna","Tidak ada implikasi perilaku"]'::jsonb, 'Nilai kini dibesar-besarkan lawan masa depan', 'Dua juta tahun depan atau satu setengah sekarang—kenapa sekarang menang terus?', 'Nilai masa depan sering didiskon berlebihan di kepala dibanding angka netral.', 'Present bias membuat tabungan otomatis lebih efektif daripada niat manual bulan depan.', 'Hari esok mudah ditunda otak.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (98, 10, 'Hindari penyesalan', 'Meniru portofolio tetangga sering untuk menghindari?', '["Rasa menyesal jika dia untung dan kamu tidak","Risiko identik objektif","Biaya transaksi tambahan semata"]'::jsonb, 'Rasa menyesal jika dia untung dan kamu tidak', 'Tetangga pamer cuan—kamu ikut beli biar tenang hati?', 'Regret avoidance mendorong herding meski toleransi risiko beda.', 'Investor meniru orang lain untuk minimalkan counterfactual fomo penyesalan pribadi relatif.', 'Ikut tetangga demi hati tenang.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (99, 10, 'Bias perencanaan', 'Kita sering meremehkan berapa lama proyek finansial selesai karena?', '["Kekeliruan perencanaan meremehkan hambatan dan gangguan","Otak memperkirakan waktu terlalu panjang selalu","Data historis menyebabkan kehati-hatian ekstrem"]'::jsonb, 'Kekeliruan perencanaan meremehkan hambatan dan gangguan', 'Investasi lima tahun pasti lancar—berapa kali rencana hidupmu tepat lima tahun?', 'Rencana kita bias optimistik tanpa buffer kontingen realistis.', 'Kekeliruan perencanaan bikin target terlalu ketat sehingga gampang frustrasi dan nyimpang jalur.', 'Beri ruang hambatan di rencana.');
INSERT INTO lessons (id, level, title, question, options, answer, hook, body, explanation, insight) VALUES (100, 10, 'Herding sosmed', 'Ramai posting satu saham bersamaan di timeline memicu apa?', '["Tekanan sosial beli tanpa riset pribadi","Riset mendalam otomatis tiap penonton","Penurunan FOMO pasti"]'::jsonb, 'Tekanan sosial beli tanpa riset pribadi', 'Satu kode saham penuhi feed—itu sinyal atau gema orang?', 'Popularitas online menggantikan checklist risiko pribadi dengan validasi suara banyak.', 'Herding retail memperbesar bubble lokal dan penderitaan saat likuiditas balik arah tiba.', 'Ramai online bukan riset sendiri.');
